// 从多个输入节点获取数据
const cbResult = $input.all().find(n => n.json.cb_list !== undefined)?.json || {};
const stockResult = $input.all().find(n => n.json.spot !== undefined)?.json || {};
const ctrlResult = $input.all().find(n => n.json.controller_data !== undefined)?.json || {};
const finResult = $input.all().find(n => n.json.finance_data !== undefined)?.json || {};

const cbList = cbResult.cb_list || [];
const spotList = stockResult.spot || [];
const maList = stockResult.ma || [];
const ctrlList = ctrlResult.controller_data || [];
const finList = finResult.finance_data || [];

// 转换为Map便于查找
const spotMap = Object.fromEntries(spotList.map(s => [s.正股代码, s]));
const maMap = Object.fromEntries(maList.map(m => [m.正股代码, m]));
const ctrlMap = Object.fromEntries(ctrlList.map(c => [c.正股代码, c]));
const finMap = Object.fromEntries(finList.map(f => [f.正股代码, f]));

// 合并数据
const mergedData = cbList.slice(0, 50).map(cb => {
  const stockCode = cb.正股代码 || cb.stock_code;
  const spot = spotMap[stockCode] || {};
  const ma = maMap[stockCode] || {};
  const ctrl = ctrlMap[stockCode] || {};
  const fin = finMap[stockCode] || {};

  const currentPrice = parseFloat(spot.当前股价) || 0;
  const netAsset = parseFloat(spot.每股净资产) || 1;
  const pb = currentPrice ? (currentPrice / netAsset).toFixed(2) : '';
  const convertPrice = parseFloat(cb.转股价格 || cb.convert_price) || 0;
  const strongRedeemPrice = convertPrice ? (convertPrice * 1.3).toFixed(2) : '';
  const strongRedeemPct = currentPrice ? (((parseFloat(strongRedeemPrice) / currentPrice - 1) * 100).toFixed(1) + '%') : '';
  const remainScale = parseFloat(cb.可转债剩余规模 || cb.remaining_scale) || 0;
  const expirePrice = 115;
  const expireScale = (remainScale * expirePrice / 100).toFixed(2);

  const cashEnd = fin.期末现金余额 || 0;
  const moneyFund = fin.货币资金 || 0;
  const expireCashRatio = cashEnd ? (expireScale / cashEnd * 100).toFixed(0) + '%' : '';
  const expireMoneyRatio = moneyFund ? (expireScale / moneyFund * 100).toFixed(0) + '%' : '';

  return {
    正股代码: stockCode,
    正股名称: cb.正股名称 || cb.stock_name || '',
    大股东类型: ctrl.大股东类型 || '',
    实际控制人: ctrl.实际控制人 || '',
    实控人类型: ctrl.实控人类型 || '',
    今日日期: new Date().toISOString().split('T')[0].replace(/-/g, '/'),
    当前股价: currentPrice || '',
    每股净资产: spot.每股净资产 || '',
    PB: pb,
    期末现金余额: fin.期末现金余额 || '',
    货币资金: fin.货币资金 || '',
    转债代码: cb.转债代码 || cb.bond_code || '',
    转债名称: cb.转债名称 || cb.bond_name || '',
    可转债剩余规模: remainScale || '',
    到期赎回价: expirePrice,
    到期赎回规模: expireScale,
    赎回规模占期末现金比例: expireCashRatio,
    赎回规模占货币资金比例: expireMoneyRatio,
    转股价格: convertPrice || '',
    强赎价格: strongRedeemPrice,
    强赎涨幅: strongRedeemPct,
    MA5: ma.MA5 || '',
    MA10: ma.MA10 || '',
    MA20: ma.MA20 || '',
    到期日期: cb.到期日期 || cb.expire_date || '',
    剩余天数: cb.到期日期 ? Math.floor((new Date(cb.到期日期) - new Date()) / (1000 * 60 * 60 * 24)) : '',
    最近公告内容: ''
  };
});

// 生成CSV
if (mergedData.length === 0) {
  return [{ json: { csv_content: '暂无数据', count: 0, merged_data: [] } }];
}

const headers = Object.keys(mergedData[0]);
const csvRows = [
  headers.join(','),
  ...mergedData.map(row => headers.map(h => {
    const val = row[h] ?? '';
    return String(val).includes(',') ? `"${val}"` : val;
  }).join(','))
];
const csvContent = csvRows.join('\n');

return [{ json: { csv_content: csvContent, count: mergedData.length, merged_data: mergedData } }];

const csvContent = $input.first().json.csv_content;
const count = $input.first().json.count;
const today = new Date().toISOString().split('T')[0];

const base64 = Buffer.from(csvContent, 'utf-8').toString('base64');

return [{
  json: {
    subject: `【可转债日报】${today} A股可转债统计（共${count}只）`,
    text: `今日共统计 ${count} 只可转债，详见附件。\n\n数据来源：AkShare\n生成时间：${new Date().toLocaleString('zh-CN')}`,
    fileName: `可转债统计_${today}.csv`,
    fileBase64: base64,
    fileMimeType: 'text/csv'
  }
}];
